import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './Home.css';

function Home() {
  const [cas, setCas] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:5001/api/ca')
      .then(res => {
        setCas(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  return (
    <div className="home-page">
      <header className="hero-section">
        <div className="container">
          <h1>Find the Right <span>Expertise</span> for Your Finances</h1>
          <p>Connect with top Chartered Accountants and manage your subscriptions effortlessly.</p>
        </div>
      </header>

      <main className="container">
        <section className="ca-grid-section">
          <div className="section-header">
            <h2>Top Rated Professionals</h2>
            <p>Our most highly recommended CAs based on experience and client feedback.</p>
          </div>

          {loading ? (
            <div className="loading-state">Loading experts...</div>
          ) : (
            <div className="ca-grid">
              {cas.map(ca => (
                <Link to={`/ca/${ca._id}`} key={ca._id} className="ca-card card">
                  <div className="ca-avatar">
                    {ca.name.charAt(0)}
                  </div>
                  <div className="ca-info">
                    <h3>{ca.name}</h3>
                    <div className="ca-stats">
                      <span className="stat">
                        <strong>{ca.experience}+</strong> yrs Exp
                      </span>
                      <span className="stat">
                        <strong>{ca.subscribersCount}</strong> subs
                      </span>
                    </div>
                    <p className="ca-specialization">Corporate Tax, Auditing, Financial Planning</p>
                    <button className="btn btn-primary">View Profile</button>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </section>
      </main>
    </div>
  );
}

export default Home;
